+            rollback_tx(cx, tracked).await;
+            return Outcome::Err(error);
+        }
+    };
+
+    if experience.state != new_state
+        && let Err(reason) = validate_transition(experience.state, new_state)
     {
-        Outcome::Ok(value) => value,
